static bool are_both_sensors_valid(controller_t *controller)
{
    return controller->has_valid_temperature && controller->has_valid_level;
}

static bool is_sensor_stale(uint32_t last_ms, uint32_t now_ms, uint32_t timeout_ms)
{
    if (now_ms < last_ms) {
        return false;
    }
    return (now_ms - last_ms) > timeout_ms;
}

static void apply_control_policy(controller_t *controller, controller_input_t input)
{
    int level = controller->last_level;
    int temp = controller->last_temperature_c;
    uint32_t now_ms = input.now_ms;

    /* Check for sensor timeout - both sensors stale */
    if (are_both_sensors_valid(controller)) {
        bool temp_stale = is_sensor_stale(controller->last_temperature_ms, now_ms, CONTROLLER_SENSOR_TIMEOUT_MS);
        bool level_stale = is_sensor_stale(controller->last_level_ms, now_ms, CONTROLLER_SENSOR_TIMEOUT_MS);

        if (temp_stale || level_stale) {
            controller_set_safe_idle(controller);
            return;
        }
    } else {
        /* Not both sensors valid - stay in safe idle */
        controller_set_safe_idle(controller);
        return;
    }

    /* At this point, both sensors are valid and not stale */
    bool low_level_heater_guard = (level < CONTROLLER_MIN_HEATING_LEVEL);

    /* Temperature-based decisions */
    if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* TEMP > 48: INLET CLOSED, HEATER OFF */
        controller->inlet_open = false;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_HEATING;
        return;
    }

    if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* 47 <= TEMP <= 48 */
        controller->inlet_open = false;

        bool temp_rising = (controller->previous_temperature_c < temp);

        if (low_level_heater_guard) {
            /* Level < 55: heater must be off */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_FILLING;
        } else if (temp_rising) {
            /* Temp rising at upper band: HEATER OFF early */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HEATING;
        } else {
            /* Temp not rising: hold previous safe heater state */
            /* Heater stays off if level < 55, otherwise maintain current state */
            if (level >= CONTROLLER_MIN_HEATING_LEVEL) {
                /* Hold previous heater state or default to off for safety */
                controller->heater_on = false;
            } else {
                controller->heater_on = false;
            }
            controller->state = CONTROLLER_STATE_HOLDING;
        }
        return;
    }

    if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
        /* 45 <= TEMP < 47: INLET CLOSED, hold previous safe heater state */
        controller->inlet_open = false;

        if (low_level_heater_guard) {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_FILLING;
        } else {
            /* Hold previous safe state - default to off for safety */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HEATING;
        }
        return;
    }

    /* TEMP < 45: heating phase, check level conditions */
    if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* LEVEL > 75: INLET CLOSED */
        controller->inlet_open = false;

        if (!low_level_heater_guard && temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }
    } else if (level >= CONTROLLER_FILL_LEVEL_THRESHOLD) {
        /* 60 <= LEVEL <= 75 */
        controller->inlet_open = false;

        if (!low_level_heater_guard && temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }
    } else {
        /* LEVEL < 60: INLET OPEN, HEATER OFF */
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
    }
}

